57	    while (i < prog_count) {
58	        char *ln = prog_get(i);
59	        if (is_upper(ln[0])) {
60	            int j = 1;
61	            while (is_alnum(ln[j])) j++;
62	            if (ln[j] == 58) {  // ':'
63	                int sym_idx = sym_lookup(ln, 0);
64	                if (sym_idx >= 0) {
65	                    sym_val[sym_idx] = arr_scalar(i + 1);  // 1-based line number
