77	int prog_parse_entry(char *line, char **rest) {
78	    if (line[0] != 91) return 0;  // '['
79	    int i = 1;
80	    if (!is_digit(line[i])) return 0;
81	    int num = 0;
82	    while (is_digit(line[i])) {
83	        num = num * 10 + (line[i] - 48);
84	        i++;
85	    }
86	    if (line[i] != 93) return 0;  // ']'
87	    i++;
88	    while (line[i] == 32) i++;  // skip spaces
89	    *rest = line + i;
