95	
96	    arr_reset();
97	    prog_clear();
98	    fn_reset();
99	    call_depth = 0;
100	    branch_target = -1;
101	    puts("COR24 APL v0.1");
102	
103	    int pc = -1;  // -1 = read from input, >=0 = replay stored line
104	
105	    while (1) {
106	        char *cur_line;
107	        int cur_lineno;  // 1-based line number
108	
109	        if (pc >= 0) {
110	            // Replaying stored line
111	            cur_line = prog_get(pc);
112	            cur_lineno = pc + 1;
113	        } else {
114	            // Read new line from input
115	            io_print("      ");
116	            int n = io_getline(line, IO_LINE_MAX);
117	            if (n == 0) continue;
118	
119	            // Function definition mode: collect body lines
120	            if (fn_def_mode) {
121	                int ci = 0;
122	                while (line[ci] == 32) ci++;
123	                if (str_match(line, ci, "del") == 3 && !is_alnum(line[ci + 3])) {
124	                    // Closing del
125	                    fn_def_mode = 0;
126	                } else if (fn_def_line >= FN_BODY_MAX) {
127	                    io_print("  FN FULL");
128	                    putchar(10);
129	                    fn_def_mode = 0;
130	                } else {
131	                    fn_store_line(fn_def_idx, fn_def_line, line);
132	                    fn_lines[fn_def_idx] = fn_def_line + 1;
133	                    fn_def_line++;
134	                }
135	                continue;
136	            }
137	
138	            // Check for [N] line entry syntax
139	            char *rest;
140	            int lnum = prog_parse_entry(line, &rest);
141	            if (lnum > 0 && lnum <= PROG_MAX) {
142	                prog_store(rest, lnum - 1);
143	                if (lnum > prog_count) prog_count = lnum;
144	                continue;
145	            }
146	
147	            cur_line = line;
148	            cur_lineno = 0;  // immediate mode, no line number
149	        }
150	
151	        // Check for label prefix: IDENT: at start of line
152	        char *exec_line = cur_line;
153	        if (is_upper(cur_line[0])) {
154	            int j = 1;
155	            while (is_alnum(cur_line[j])) j++;
156	            if (cur_line[j] == 58) {  // ':'
157	                // Record label as variable set to line number
158	                int sym_idx = sym_lookup(cur_line, 0);
159	                if (sym_idx >= 0) {
160	                    sym_val[sym_idx] = arr_scalar(cur_lineno);
161	                    sym_set_flag[sym_idx] = 1;
162	                }
163	                j++;
164	                while (cur_line[j] == 32) j++;
165	                exec_line = cur_line + j;
166	                if (exec_line[0] == 0) {
167	                    // Label-only line, no code to execute
168	                    if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
169	                    continue;
170	                }
171	            }
172	        }
173	
174	        if (exec_line[0] == 0) {
175	            // Empty line
176	            if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
177	            continue;
178	        } else if (exec_line[0] == 41) {
179	            // System command: starts with ')'
180	            if (str_match(exec_line, 1, "CLEAR") == 5 && (exec_line[6] == 0 || exec_line[6] == 32)) {
181	                arr_reset();
182	                sym_reset();
183	                fn_reset();
184	                io_print("  CLEAR WS");
185	                putchar(10);
186	            } else if (str_match(exec_line, 1, "VARS") == 4 && (exec_line[5] == 0 || exec_line[5] == 32)) {
187	                int i = 0;
188	                int any = 0;
189	                while (i < sym_count) {
190	                    if (sym_set_flag[i]) {
191	                        if (any) io_print("  ");
192	                        int off = sym_name_off[i];
193	                        while (sym_name_buf[off]) {
194	                            putchar(sym_name_buf[off]);
195	                            off++;
196	                        }
197	                        any = 1;
198	                    }
199	                    i++;
200	                }
201	                if (any) putchar(10);
202	            } else if (str_match(exec_line, 1, "LIST") == 4 && (exec_line[5] == 0 || exec_line[5] == 32)) {
203	                int i = 0;
204	                while (i < prog_count) {
205	                    char *ln = prog_get(i);
206	                    if (ln[0]) {
207	                        putchar(91);  // '['
208	                        print_int(i + 1);
209	                        putchar(93);  // ']'
210	                        putchar(32);
211	                        io_print(ln);
212	                        putchar(10);
213	                    }
214	                    i++;
215	                }
216	            } else if (str_match(exec_line, 1, "RUN") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
217	                if (prog_count > 0) {
218	                    prog_scan_labels();
219	                    pc = 0;
220	                    branch_target = -1;
221	                    continue;
222	                }
223	            } else if (str_match(exec_line, 1, "ERASE") == 5 && (exec_line[6] == 0 || exec_line[6] == 32)) {
224	                prog_clear();
225	            } else if (str_match(exec_line, 1, "FNS") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
226	                int i = 0;
227	                int any = 0;
228	                while (i < fn_count) {
229	                    int sym = fn_name_sym[i];
230	                    if (any) io_print("  ");
231	                    int off = sym_name_off[sym];
232	                    while (sym_name_buf[off]) {
233	                        putchar(sym_name_buf[off]);
234	                        off++;
235	                    }
236	                    any = 1;
237	                    i++;
238	                }
239	                if (any) putchar(10);
240	            } else if (str_match(exec_line, 1, "OFF") == 3 && (exec_line[4] == 0 || exec_line[4] == 32)) {
241	                return 0;
242	            } else {
243	                io_print("  SYNTAX ERROR");
244	                putchar(10);
245	            }
246	        } else {
247	            // Check for "del" function definition (before tokenize, since
248	            // the tokenizer rejects unknown lowercase words)
249	            int di = 0;
250	            while (exec_line[di] == 32) di++;
251	            if (str_match(exec_line, di, "del") == 3 &&
252	                (exec_line[di + 3] == 0 || exec_line[di + 3] == 32)) {
253	                int after = di + 3;
254	                while (exec_line[after] == 32) after++;
255	                if (exec_line[after] == 0) {
256	                    // Bare "del" outside definition mode
257	                    io_print("  SYNTAX ERROR");
258	                    if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
259	                    putchar(10);
260	                } else if (pc >= 0) {
261	                    // Can't define functions during program execution
262	                    io_print("  SYNTAX ERROR");
263	                    io_print(" ["); print_int(pc + 1); putchar(93); pc = -1;
264	                    putchar(10);
265	                } else {
266	                    // Start function definition
267	                    int temp = fn_count;
268	                    if (temp >= FN_MAX) {
269	                        io_print("  FN TABLE FULL");
270	                        putchar(10);
271	                    } else if (!parse_fn_header(exec_line + after, temp)) {
272	                        io_print("  SYNTAX ERROR");
273	                        putchar(10);
274	                    } else {
275	                        // Check for existing function with same name
276	                        int ns = fn_name_sym[temp];
277	                        int exi = 0;
278	                        int found = -1;
279	                        while (exi < fn_count) {
280	                            if (fn_name_sym[exi] == ns) found = exi;
281	                            exi++;
282	                        }
283	                        if (found >= 0) {
284	                            // Redefine existing function
285	                            fn_result_sym[found] = fn_result_sym[temp];
286	                            fn_right_sym[found] = fn_right_sym[temp];
287	                            fn_left_sym[found] = fn_left_sym[temp];
288	                            fn_lines[found] = 0;
289	                            fn_def_idx = found;
290	                        } else {
291	                            fn_count++;
292	                            fn_def_idx = temp;
293	                        }
294	                        fn_def_mode = 1;
295	                        fn_def_line = 0;
296	                    }
297	                }
298	                if (pc >= 0) { pc++; if (pc >= prog_count) pc = -1; }
299	                continue;
300	            }
301	
302	            int ntok = tokenize(exec_line);
303	            if (ntok < 0) {
304	                io_print("  SYNTAX ERROR");
305	                if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
306	                putchar(10);
307	            } else {
308	                // Save heap position for temporary reclamation
309	                int heap_save = heap_top;
310	
311	                int root = parse(exec_line);
312	                if (root < 0) {
313	                    heap_top = heap_save;
314	                    io_print("  SYNTAX ERROR");
315	                    if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
316	                    putchar(10);
317	                } else {
318	                    eval_err = 0;
319	                    branch_target = -1;
320	                    int result = eval(root);
321	                    if (eval_err == 2) {
322	                        heap_top = heap_save;
323	                        io_print("  VALUE ERROR");
324	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
325	                        putchar(10);
326	                    } else if (eval_err == 3) {
327	                        heap_top = heap_save;
328	                        io_print("  LENGTH ERROR");
329	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
330	                        putchar(10);
331	                    } else if (eval_err == 4) {
332	                        heap_top = heap_save;
333	                        io_print("  RANK ERROR");
334	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
335	                        putchar(10);
336	                    } else if (eval_err == 5) {
337	                        heap_top = heap_save;
338	                        io_print("  WS FULL");
339	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
340	                        putchar(10);
341	                    } else if (eval_err) {
342	                        heap_top = heap_save;
343	                        io_print("  DOMAIN ERROR");
344	                        if (pc >= 0) { io_print(" ["); print_int(pc + 1); putchar(93); pc = -1; }
345	                        putchar(10);
346	                    } else if (node_type[root] == NODE_ASSIGN) {
347	                        // Assignment: no output (APL convention)
348	                        // Don't restore heap -- variable value persists
349	                    } else if (node_type[root] == NODE_QLED_ASSIGN) {
350	                        // Quad LED assignment: no output
351	                        heap_top = heap_save;
352	                    } else if (node_type[root] == NODE_SVO_WRITE) {
353	                        // Shared variable indexed write: no output
354	                        heap_top = heap_save;
355	                    } else if (node_type[root] == NODE_GOTO || node_type[root] == NODE_CGOTO) {
356	                        // Branch: no output
357	                        heap_top = heap_save;
358	                    } else {
359	                        // Print result based on rank
360	                        int rank = arr_rank(result);
361	                        if (rank == 0) {
362	                            io_print("  ");
363	                            print_int(arr_get(result, 0));
364	                            putchar(10);
365	                        } else if (rank == 1) {
366	                            int sz = arr_dim0(result);
367	                            // Find max width across all elements
368	                            int maxw = 1;
369	                            int j = 0;
370	                            while (j < sz) {
371	                                int w = num_width(arr_get(result, j));
372	                                if (w > maxw) maxw = w;
373	                                j++;
374	                            }
375	                            // Print each element right-justified
376	                            j = 0;
377	                            while (j < sz) {
378	                                if (j == 0) putchar(32);
379	                                print_int_rj(arr_get(result, j), maxw);
380	                                if (j + 1 < sz) putchar(32);
381	                                j++;
382	                            }
383	                            putchar(10);
384	                        } else if (rank == 2) {
385	                            int rows = arr_dim0(result);
386	                            int cols = arr_dim1(result);
387	                            int sz = rows * cols;
388	                            // Find max width across all elements
389	                            int maxw = 1;
390	                            int j = 0;
391	                            while (j < sz) {
392	                                int w = num_width(arr_get(result, j));
393	                                if (w > maxw) maxw = w;
394	                                j++;
395	                            }
396	                            // Print each row on its own line
397	                            int r = 0;
398	                            while (r < rows) {
399	                                int c = 0;
400	                                while (c < cols) {
401	                                    if (c == 0) putchar(32);
402	                                    print_int_rj(arr_get(result, r * cols + c), maxw);
403	                                    if (c + 1 < cols) putchar(32);
404	                                    c++;
405	                                }
406	                                putchar(10);
407	                                r++;
408	                            }
409	                        }
410	                        // Reclaim temporaries
411	                        heap_top = heap_save;
412	                    }
413	                }
414	            }
415	        }
416	
417	        // Check for branch
418	        if (branch_target > 0) {
419	            pc = branch_target - 1;  // convert 1-based to 0-based
420	            branch_target = -1;
421	            continue;
422	        } else if (branch_target == 0) {
423	            // goto 0: stop execution
424	            if (pc >= 0) {
425	                // In program mode: return to immediate mode
426	                pc = -1;
427	                branch_target = -1;
428	                continue;
429	            }
430	            // In immediate mode: exit interpreter
431	            return 0;
432	        }
433	
434	        // Advance PC if replaying stored lines
435	        if (pc >= 0) {
436	            pc++;
437	            if (pc >= prog_count) pc = -1;
438	        }
439	    }
440	    return 0;
441	}
