                int sym_idx = sym_lookup(cur_line, 0);
                if (sym_idx >= 0) {
                    sym_val[sym_idx] = arr_scalar(cur_lineno);
                    sym_set_flag[sym_idx] = 1;
                }
                j++;
                while (cur_line[j] == 32) j++;
                exec_line = cur_line + j;
                if (exec_line[0] == 0) {
