             // Read new line from input
-            io_print("      ");
-            int n = io_getline(line, IO_LINE_MAX);
+            int n;
+            if (batch_mode) {
+                n = batch_getline(line, IO_LINE_MAX);
+                if (n < 0) {
+                    // End of image -- switch to interactive mode
+                    batch_mode = 0;
+                    continue;
+                }
+            } else {
+                io_print("      ");
+                n = io_getline(line, IO_LINE_MAX);
+            }
             if (n == 0) continue;

